import{_ as s,C as l,o as n,c as o,E as a,w as r,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const f=JSON.parse('{"title":"Hungary Healthcare & HRT","description":"Transgender healthcare access in Hungary","frontmatter":{"layout":"doc","title":"Hungary Healthcare & HRT","description":"Transgender healthcare access in Hungary"},"headers":[],"relativePath":"europe/hungary/healthcare.md","filePath":"europe/hungary/healthcare.md","lastUpdated":null}'),c={name:"europe/hungary/healthcare.md"};function h(u,e,g,p,y,m){const t=l("Badge");return n(),o("div",null,[a(t,{variant:"red"},{default:r(()=>[...e[0]||(e[0]=[i("Very Restricted Access",-1)])]),_:1}),a(t,{variant:"yellow"},{default:r(()=>[...e[1]||(e[1]=[i("HRT Available (Limited)",-1)])]),_:1}),a(t,{variant:"yellow"},{default:r(()=>[...e[2]||(e[2]=[i("Under Political Pressure",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="healthcare-hrt-in-hungary" tabindex="-1">Healthcare &amp; HRT in Hungary <a class="header-anchor" href="#healthcare-hrt-in-hungary" aria-label="Permalink to &quot;Healthcare &amp; HRT in Hungary&quot;">​</a></h1><h2 id="gatekeeping-model" tabindex="-1">Gatekeeping Model <a class="header-anchor" href="#gatekeeping-model" aria-label="Permalink to &quot;Gatekeeping Model&quot;">​</a></h2><p>Hungary&#39;s transgender healthcare system is <strong>restricted and under increasing political pressure</strong>:</p><ul><li><strong>Psychiatric diagnosis required</strong> for access to HRT</li><li>Services concentrated in <strong>Budapest</strong></li><li>Growing difficulty accessing care due to political climate</li><li>Some providers have stopped offering trans healthcare due to fear of repercussions</li></ul><h2 id="accessing-hrt" tabindex="-1">Accessing HRT <a class="header-anchor" href="#accessing-hrt" aria-label="Permalink to &quot;Accessing HRT&quot;">​</a></h2><h3 id="step-1-psychiatric-assessment" tabindex="-1">Step 1: Psychiatric Assessment <a class="header-anchor" href="#step-1-psychiatric-assessment" aria-label="Permalink to &quot;Step 1: Psychiatric Assessment&quot;">​</a></h3><ul><li>Contact a psychiatrist or sexologist in Budapest</li><li>Major hospitals include Semmelweis University and the National Institute of Psychiatry</li><li>Diagnosis of gender dysphoria per ICD-10/11 required</li><li>Multiple sessions over several months</li><li>Wait times are increasing as providers leave the field</li></ul><h3 id="step-2-endocrinology-referral" tabindex="-1">Step 2: Endocrinology Referral <a class="header-anchor" href="#step-2-endocrinology-referral" aria-label="Permalink to &quot;Step 2: Endocrinology Referral&quot;">​</a></h3><ul><li>Referral to an endocrinologist for hormone therapy</li><li>Baseline blood tests required</li><li>HRT prescribed and monitored</li><li>Follow-up visits every 3-6 months</li></ul><h3 id="step-3-ongoing-care" tabindex="-1">Step 3: Ongoing Care <a class="header-anchor" href="#step-3-ongoing-care" aria-label="Permalink to &quot;Step 3: Ongoing Care&quot;">​</a></h3><ul><li>Regular monitoring by endocrinologist</li><li>Some medications may need to be sourced from abroad</li><li>Growing difficulty finding providers willing to treat trans patients</li></ul><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>Semmelweis University</td><td>Budapest</td><td>Psychiatry, endocrinology</td></tr><tr><td>National Institute of Psychiatry</td><td>Budapest</td><td>Psychiatric assessment</td></tr><tr><td>Private sexologists</td><td>Budapest</td><td>Assessment (shorter waits)</td></tr><tr><td>Private endocrinologists</td><td>Budapest</td><td>HRT (limited trans experience)</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU prescriptions</strong>: Valid in Hungary under EU mutual recognition</li><li><strong>Non-EU prescriptions</strong>: Must be re-evaluated by a Hungarian doctor</li><li><strong>Importing medication</strong>: 3-month supply permitted with a doctor&#39;s letter</li><li><strong>Stock issues</strong>: Some HRT medications may be unavailable</li><li><strong>Pharmacies</strong>: Major chains (Gyógyszertár) in Budapest and larger cities</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li><strong>No gender-affirming surgeries available</strong> in Hungary</li><li>Previous providers have discontinued services</li><li>All surgeries require travel abroad</li><li>No public funding available</li><li>No established referral pathways</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Hungarian Resident</th><th>Non-Resident</th></tr></thead><tbody><tr><td>Psychiatric assessment</td><td>Free (public)</td><td>€60-120</td></tr><tr><td>Endocrinology visit</td><td>Free (public)</td><td>€50-100</td></tr><tr><td>HRT (monthly)</td><td>€15-30</td><td>€20-50</td></tr><tr><td>Private specialist</td><td>€40-80</td><td>€50-100</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://semmelweis.hu/" target="_blank" rel="noreferrer">Semmelweis University</a></li><li><a href="https://en.hatter.hu/" target="_blank" rel="noreferrer">Háttér Society - Healthcare Guide</a></li><li><a href="https://transvanilla.hu/" target="_blank" rel="noreferrer">Transvanilla Transgender Association</a></li><li><a href="https://www.bm.gov.hu/" target="_blank" rel="noreferrer">Hungarian Ministry of Health</a></li></ul>',21))])}const v=s(c,[["render",h]]);export{f as __pageData,v as default};
